import{_ as r,o as a,c as e,ae as o}from"./chunks/framework.DrYEjkpc.js";const b=JSON.parse('{"title":"SkillRouter","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillrouter.md","filePath":"radar/tech-skillrouter.md"}'),l={name:"radar/tech-skillrouter.md"};function i(n,t,h,d,s,u){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="skillrouter" tabindex="-1">SkillRouter <a class="header-anchor" href="#skillrouter" aria-label="Permalink to &quot;SkillRouter&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 召回 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.64</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 在 80K Skill 池上证明&quot;<strong>全文检索是不可绕过的必要条件</strong>&quot; —— 1.2B 模型比 16B 基线<strong>少 13× 参数、快 5.8×</strong>，端到端 Hit@1 <strong>74%</strong>。</p><p><strong>来源</strong>:</p><ul><li>学术研究</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2603.22455" target="_blank" rel="noreferrer">arXiv 2603.22455</a></li><li>GitHub：<a href="https://github.com/zhengyanzhao1997/SkillRouter" target="_blank" rel="noreferrer">zhengyanzhao1997/SkillRouter</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="两阶段检索-重排" tabindex="-1">两阶段检索 - 重排 <a class="header-anchor" href="#两阶段检索-重排" aria-label="Permalink to &quot;两阶段检索 - 重排&quot;">​</a></h3><ol><li><strong>双编码器检索（粗排）</strong> —— Qwen3-Emb-0.6B 把查询与全量 Skill 向量化，检索 Top-20 候选</li><li><strong>交叉编码器重排（细排）</strong> —— SR-Rank-0.6B 通过交叉注意力做精细化相关性打分</li></ol><h3 id="推翻-标题-简介够用-的设计假设" tabindex="-1">推翻&quot;标题+简介够用&quot;的设计假设 <a class="header-anchor" href="#推翻-标题-简介够用-的设计假设" aria-label="Permalink to &quot;推翻&quot;标题+简介够用&quot;的设计假设&quot;">​</a></h3><p>在 ~80K Skill 池上实验，<strong>隐藏 Skill body 后路由准确率暴跌 31-44 个百分点</strong>。</p><blockquote><p>两本书封面都写&quot;数据可视化指南&quot;，但一本教 Python Matplotlib，另一本教 Excel —— 不翻开内容根本分不清。</p></blockquote><h3 id="紧凑高效" tabindex="-1">紧凑高效 <a class="header-anchor" href="#紧凑高效" aria-label="Permalink to &quot;紧凑高效&quot;">​</a></h3><ul><li>1.2B 总参数量 vs 16B Qwen3 基线（Hit@1 0.641 vs 0.637）</li><li><strong>参数量减少 13×</strong>、<strong>推理速度快 5.8×</strong></li><li>可部署在消费级硬件上</li></ul><h3 id="端到端验证" tabindex="-1">端到端验证 <a class="header-anchor" href="#端到端验证" aria-label="Permalink to &quot;端到端验证&quot;">​</a></h3><p>不止&quot;路由准了&quot;就完事 —— 在 Kimi-K2.5、GLM-5、Claude Sonnet/Opus 4.6 四个主流 Agent 上验证，路由准确率提升<strong>确实转化为最终任务成功率提升</strong>。</p><h3 id="实验结果" tabindex="-1">实验结果 <a class="header-anchor" href="#实验结果" aria-label="Permalink to &quot;实验结果&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>结果</th></tr></thead><tbody><tr><td>检索阶段 Hit@1</td><td>65.4%（超越 13× 参数量的 8B 基线）</td></tr><tr><td>端到端 Hit@1</td><td><strong>74.0%</strong>（比最优零样本 8B 基线 +6pp）</td></tr><tr><td>重排序器价值</td><td>修复 12.7% 的检索失败案例</td></tr></tbody></table><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>74% Hit@1 意味着仍有 26% 首选路由错误</li><li>只做单次&quot;选哪个 Skill&quot;决策，<strong>不涉及多 Skill 动态编排</strong></li><li>识别出&quot;相似 Skill&quot;后没有方案做自动合并</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.75</td><td>论文 + 开源 + 四 Agent 端到端验证</td></tr><tr><td>创新性</td><td>0.70</td><td>实证推翻&quot;元数据优先&quot;的设计共识</td></tr><tr><td>落地程度</td><td>0.55</td><td>架构轻量化适合落地，但产品化少</td></tr><tr><td>生态活跃度</td><td>0.50</td><td>学术阶段</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.64</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2603.22455" target="_blank" rel="noreferrer">SkillRouter 论文</a></li><li><a href="https://github.com/zhengyanzhao1997/SkillRouter" target="_blank" rel="noreferrer">GitHub</a></li></ul>',33)])])}const c=r(l,[["render",i]]);export{b as __pageData,c as default};
